package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.criteria.Criterium;
import be.schaubroeck.lpb.tools.service.util.StandaardAlService;
import be.schaubroeck.lpb.tools.service.util.TemporalUtil;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import be.schaubroeck.util.persistence.Identifiable;
import org.joda.time.LocalDateTime;

import java.util.HashSet;
import java.util.Set;
import java.util.stream.Collectors;

public abstract class StandaardALCachedService<T extends Identifiable> {

    public abstract StandaardAlService<T> standaardAlService();

    @InitializeAdmin
    public Set<T> findByIds(Set<Integer> ids) {
        return findByIds(ids, "");
    }

    @InitializeAdmin
    public Set<T> findByObjectIds(Set<T> objects) {
        return findByObjectIds(objects, "");
    }

    @InitializeAdmin
    public Set<T> findByIds(Set<Integer> ids, String fetchString) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch(fetchString);
        cb.and("id", Criterium.IN(ids));
        return new HashSet<>(standaardAlService().findByCriteria(cb));
    }

    @InitializeAdmin
    public Set<T> findByObjectIds(Set<T> objects, String fetchString) {
        Set<Integer> ids = objects.stream()
                .map(Identifiable::getId)
                .collect(Collectors.toSet());

        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch(fetchString);
        cb.and("id", Criterium.IN(ids));
        return new HashSet<>(standaardAlService().findByCriteria(cb));
    }

    @InitializeAdmin
    public Set<T> findByIdsByRecordTime(Set<Integer> ids, LocalDateTime tijdstip, String fetchString) {
        return TemporalUtil.getRecordTime(tijdstip, () -> findByIds(ids, fetchString));
    }

    @InitializeAdmin
    public Set<T> findByObjectIdsByRecordTime(Set<T> objects, LocalDateTime tijdstip, String fetchString) {
        return TemporalUtil.getRecordTime(tijdstip, () -> findByObjectIds(objects, fetchString));
    }
}
